import{c as e}from"./app.39e71802.js";import{_ as c}from"./plugin-vue_export-helper.21dcd24c.js";const d={},o=e('<p>\u77E5\u6211\u8005\u8C13\u6211\u5FC3\u5FE7\uFF0C\u4E0D\u77E5\u6211\u8005\u8C13\u6211\u4F55\u6C42</p><h2 id="\u5F15\u8A00" tabindex="-1"><a class="header-anchor" href="#\u5F15\u8A00" aria-hidden="true">#</a> \u5F15\u8A00</h2><p>\u5728Vue.js\u4E4B\u4E2D\uFF0CVue\u4F1A\u81EA\u52A8\u8DDF\u8E2AJavaScript\u72B6\u6001\u53D8\u5316\u5E76\u5728\u72B6\u6001\u53D1\u751F\u6539\u53D8\u65F6\u54CD\u5E94\u5F0F\u5730\u66F4\u65B0DOM\uFF0C\u8FD9\u5C31\u662FVue.js\u7684\u4E24\u5927\u6838\u5FC3\u529F\u80FD\u4E4B\u4E00\u2014\u2014<strong>\u54CD\u5E94\u6027</strong>\uFF0C\u662F\u6BCF\u4E00\u4E2AVue.js\u6846\u67B6\u4F7F\u7528\u8005\u5FC5\u987B\u719F\u7EC3\u638C\u63E1\u7684\u7684\u529F\u80FD\u3002\u800C\u5F97\u76CA\u4E8EVue.js\u81EA\u8EAB\u652F\u6301\u7684\u58F0\u660E\u5F0F\u6E32\u67D3\uFF0CVue.js\u7684\u5B66\u4E60\u6210\u672C\u5927\u5927\u964D\u4F4E\uFF0C\u5C31\u7B97\u662F\u4E00\u4E2A\u524D\u7AEF\u9886\u57DF\u7684\u5C0F\u767D\uFF0C\u53EA\u8981\u80FD\u770B\u61C2\u5E76\u7B80\u5355\u4F7F\u7528\u57FA\u672C\u7684<code>HTML</code>\u3001<code>JavaScript</code>\u4EE5\u53CA<code>CSS</code>\uFF0C\u5C31\u80FD\u591F\u5F88\u5FEB\u4E0A\u624BVue.js\u3002\u5B66\uFF0C\u786E\u5B9E\u597D\u5B66\uFF1B\u7528\uFF0C\u771F\u7684\u597D\u7528\uFF01\u4F46\uFF0C\u4F60\u5BF9Vue.js\u6846\u67B6\u7684\u5185\u90E8\u5B9E\u73B0\u539F\u7406\u638C\u63E1\u591A\u5C11\u5462\uFF1F\u4ECA\u5929\uFF0C\u5C31\u8BA9\u6211\u4EEC\u4E00\u8D77\u6765\u7B80\u5355\u590D\u73B0\u4E00\u4E0BVue.js\u6570\u636E\u54CD\u5E94\u5F0F\u3002</p><h2 id="\u57FA\u672C\u6982\u5FF5" tabindex="-1"><a class="header-anchor" href="#\u57FA\u672C\u6982\u5FF5" aria-hidden="true">#</a> \u57FA\u672C\u6982\u5FF5</h2><h3 id="\u526F\u4F5C\u7528\u51FD\u6570" tabindex="-1"><a class="header-anchor" href="#\u526F\u4F5C\u7528\u51FD\u6570" aria-hidden="true">#</a> \u526F\u4F5C\u7528\u51FD\u6570</h3><p>\u4EC0\u4E48\u662F\u526F\u4F5C\u7528\u51FD\u6570\uFF1F\u610F\u5982\u5176\u540D\uFF0C\u526F\u4F5C\u7528\u51FD\u6570\u6307\u7684\u5C31\u662F\u4F1A\u4EA7\u751F\u526F\u4F5C\u7528\u7684\u51FD\u6570\u3002\u4EC0\u4E48\u662F\u526F\u4F5C\u7528\u5462\uFF1F\u5C31\u662F\u4F1A\u5BF9\u51FD\u6570\u4F5C\u7528\u57DF\u5916\u7684\u5176\u4ED6\u90E8\u5206\u4EA7\u751F\u5F71\u54CD\u3002\u4FD7\u8BDD\u8BF4\uFF1A\u662F\u836F\u4E09\u5206\u6BD2\uFF0C\u80FD\u6CBB\u75C5\uFF0C\u4EA6\u80FD\u81F4\u75C5\u3002\u836F\uFF0C\u5C31\u6709\u526F\u4F5C\u7528\uFF0C\u526F\u4F5C\u7528\u51FD\u6570\u4E5F\u662F\u3002</p><p>\u526F\u4F5C\u7528\u51FD\u6570\u4EE3\u7801\u793A\u4F8B\u5982\u4E0B\uFF1A</p><p><img src="https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/d898efff343f490b96c450e1840d5a3a~tplv-k3u1fbpfcp-watermark.image?" alt="carbon (39).png"></p><p>\u5F53<code>effect</code>\u51FD\u6570\u6267\u884C\u65F6\uFF0C\u5B83\u4F1A\u8BBE\u7F6E<code>body</code>\u7684\u6587\u672C\u5185\u5BB9\uFF0C\u4ECE\u800C\u76F4\u63A5\u6216\u95F4\u63A5\u5F71\u54CD\u5230\u5176\u4ED6\u4EFB\u4F55\u5BF9<code>body</code>\u6587\u672C\u5185\u5BB9\u6709\u6240\u4F9D\u8D56\u7684\u51FD\u6570\u7684\u6267\u884C\u3002\u8FD9\u5C31\u662F\u4E00\u4E2A\u7B80\u5355\u7684\u526F\u4F5C\u7528\u51FD\u6570\u3002</p><h3 id="\u54CD\u5E94\u5F0F\u6570\u636E" tabindex="-1"><a class="header-anchor" href="#\u54CD\u5E94\u5F0F\u6570\u636E" aria-hidden="true">#</a> \u54CD\u5E94\u5F0F\u6570\u636E</h3><p>\u4EE5\u6211\u7684\u7406\u89E3\uFF0C\u76F8\u8F83\u201C\u54CD\u5E94\u5F0F\u6570\u636E\u201D\u800C\u8A00\u66F4\u76F4\u767D\u7684\u53EB\u6CD5\u5E94\u8BE5\u662F\u201C\u526F\u4F5C\u7528\u6570\u636E\u201D\uFF0C\u5C31\u597D\u50CF\u526F\u4F5C\u7528\u51FD\u6570\u7684\u6267\u884C\u53EF\u80FD\u4F1A\u5F71\u54CD\u5230\u51FD\u6570\u4F5C\u7528\u57DF\u5916\u7684\u5176\u4ED6\u5185\u5BB9\u4E00\u6837\uFF0C\u201C\u526F\u4F5C\u7528\u6570\u636E\u201D\u7684\u66F4\u6539\u53EF\u80FD\u4F1A\u76F4\u63A5\u6216\u95F4\u63A5\u5F71\u54CD\u5230\u6240\u6709\u4F9D\u8D56\u8BE5\u6570\u636E\u7684\u51FD\u6570\u3002</p><p>\u5047\u54CD\u5E94\u5F0F\u6570\u636E\u4EE3\u7801\u793A\u4F8B\u5982\u4E0B\uFF1A</p><p><img src="https://p6-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/c0ae1fccca2b4ef1a102459ffc6743e3~tplv-k3u1fbpfcp-watermark.image?" alt="carbon (41).png"></p><p>\u5982\u4E0A\u56FE\uFF0C\u5047\u8BBE\u6BCF\u4E00\u6B21\u4FEE\u6539\u5BF9\u8C61<code>obj</code>\u7684<code>text</code>\u5C5E\u6027\u503C\uFF0C\u90FD\u4F1A\u89E6\u53D1\u51FD\u6570<code>effect</code>\u7684\u91CD\u65B0\u6267\u884C\uFF0C\u90A3\u4E48\u5C31\u53EF\u4EE5\u8BF4\u5BF9\u8C61<code>obj</code>\u662F\u4E00\u4E2A\u54CD\u5E94\u5F0F\u6570\u636E\u3002\u5F53\u7136\uFF0C\u5728\u8FD9\u4E2A\u793A\u4F8B\u91CC\uFF0C\u5B9E\u9645\u4E0A\u5E76\u6CA1\u6709\u5B9E\u73B0\u5BF9<code>obj</code>\u5BF9\u8C61\u7684\u6570\u636E\u54CD\u5E94\u3002</p><h2 id="\u54CD\u5E94\u5F0F\u6570\u636E\u7684\u57FA\u672C\u5B9E\u73B0" tabindex="-1"><a class="header-anchor" href="#\u54CD\u5E94\u5F0F\u6570\u636E\u7684\u57FA\u672C\u5B9E\u73B0" aria-hidden="true">#</a> \u54CD\u5E94\u5F0F\u6570\u636E\u7684\u57FA\u672C\u5B9E\u73B0</h2><h3 id="\u5B9E\u73B0\u601D\u8DEF" tabindex="-1"><a class="header-anchor" href="#\u5B9E\u73B0\u601D\u8DEF" aria-hidden="true">#</a> \u5B9E\u73B0\u601D\u8DEF</h3><p>\u4ED4\u7EC6\u89C2\u5BDF\u601D\u8003\u4E0A\u8FF0\u7684\u4F8B\u5B50\uFF0C\u4F60\u53EF\u80FD\u4F1A\u53D1\u73B0\u54CD\u5E94\u5F0F\u6570\u636E\u7684\u5B9E\u73B0\u5B58\u5728\u4E24\u4E2A\u5173\u952E\u70B9\uFF1A</p><ul><li>\u526F\u4F5C\u7528\u51FD\u6570<code>effect</code>\u7684\u6267\u884C\u4F1A\u89E6\u53D1\u5B57\u6BB5<code>obj.text</code>\u7684\u8BFB\u53D6\u64CD\u4F5C</li><li>\u54CD\u5E94\u5F0F\u6570\u636E<code>obj.text</code>\u503C\u7684\u4FEE\u6539\u4F1A\u89E6\u53D1\u5B57\u6BB5<code>obj.text</code>\u7684\u8BBE\u7F6E\u64CD\u4F5C</li></ul><p>\u4E8B\u60C5\u7684\u8109\u7EDC\u6E10\u6E10\u6E05\u6670\u8D77\u6765\uFF1A\u5982\u679C\u6211\u4EEC\u80FD\u591F\u62E6\u622A\u5BF9\u8C61<code>obj</code>\u7684\u8BFB\u53D6\u548C\u8BBE\u7F6E\u64CD\u4F5C\uFF0C\u5728\u526F\u4F5C\u7528\u51FD\u6570<code>effect</code>\u9996\u6B21\u8BFB\u53D6\u5B57\u6BB5<code>obj.text</code>\u7684\u503C\u65F6\u5C06\u5B83\u4E0E\u5BF9\u8C61<code>obj</code>\u5173\u8054\u8D77\u6765\uFF0C\u6B64\u540E\u6BCF\u6B21\u91CD\u65B0\u8BBE\u7F6E\u5B57\u6BB5<code>obj.text</code>\u7684\u503C\uFF0C\u90FD\u4F1A\u91CD\u65B0\u8C03\u7528\u4E00\u6B21<code>effect</code>\u51FD\u6570\uFF0C\u8FD9\u6837\u4E0D\u5C31\u7B80\u5355\u7684\u5B9E\u73B0\u4E86\u5BF9<code>obj</code>\u5BF9\u8C61\u7684\u54CD\u5E94\u5417\uFF1F</p><h3 id="\u521D\u6B65\u5B9E\u73B0\u5C1D\u8BD5" tabindex="-1"><a class="header-anchor" href="#\u521D\u6B65\u5B9E\u73B0\u5C1D\u8BD5" aria-hidden="true">#</a> \u521D\u6B65\u5B9E\u73B0\u5C1D\u8BD5</h3><p>\u5B9E\u73B0\u7684\u601D\u8DEF\u6709\u4E86\uFF0C\u90A3\u73B0\u5728\u6700\u5173\u952E\u7684\u95EE\u9898\u5C31\u662F\uFF1A\u5982\u4F55\u5B9E\u73B0\u62E6\u622A\u4E00\u4E2A\u5BF9\u8C61\u5C5E\u6027\u7684\u8BFB\u53D6\u548C\u8BBE\u7F6E\u64CD\u4F5C\u3002\u5982\u679C\u4F60\u5BF9JavaScript\u8DB3\u591F\u719F\u6089\uFF0C\u4F60\u53EF\u80FD\u5C31\u4F1A\u60F3\u5230<code>Object.defineProperty</code>\u51FD\u6570\u4EE5\u53CA<code>Proxy</code>\u5BF9\u8C61\u4EE3\u7406\u3002\u662F\u7684\uFF0C\u8FD9\u4E24\u79CD\u65B9\u6848\u90FD\u53EF\u4EE5\u5B9E\u73B0\u62E6\u622A\u4E00\u4E2A\u5BF9\u8C61\u5C5E\u6027\u7684\u8BFB\u53D6\u4EE5\u53CA\u8BBE\u7F6E\u64CD\u4F5C\u3002\u4E8B\u5B9E\u4E0A\uFF0C\u7528<code>Object.defineProperty</code>\u51FD\u6570\u5B9E\u73B0\u6570\u636E\u54CD\u5E94\u6B63\u662FVue.js 2\u4E2D\u6240\u91C7\u7528\u7684\u65B9\u6CD5\uFF0C\u800C<code>Proxy</code>\u5BF9\u8C61\u4EE3\u7406\u5219\u6B63\u662FVue.js 3\u4E2D\u6240\u91C7\u7528\u7684\u65B9\u6CD5\u3002</p><p>\u63A5\u4E0B\u6765\u8BA9\u6211\u4EEC\u987A\u7740\u4E0A\u9762\u7684\u601D\u8DEF\u91C7\u7528<code>proxy</code>\u5B9E\u73B0\u4E00\u4E0B\uFF1A</p><p><img src="https://p9-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/5d77b768c4454cbbb052358298dbb7dd~tplv-k3u1fbpfcp-watermark.image?" alt="carbon (42).png"></p><p>\u8FD9\u5C31\u662F\u91C7\u7528<code>Proxy</code>\u4EE3\u7406\u5BF9\u8C61\u7B80\u5355\u5B9E\u73B0\u7684\u6570\u636E\u54CD\u5E94\u5F0F\uFF0C\u4F60\u5B8C\u5168\u53EF\u4EE5\u81EA\u884C\u521B\u5EFA\u4E00\u4E2A\u526F\u4F5C\u7528\u51FD\u6570<code>effect</code>\u8FDB\u884C\u6D4B\u8BD5\u3002\u5F53\u7136\uFF0C\u8003\u8651\u5230\u590D\u6742\u591A\u53D8\u7684\u73AF\u5883\uFF0C\u6B64\u65F6\u7684\u6570\u636E\u76F8\u5E94\u5F0F\u8FD8\u6709\u5F88\u591A\u7EE7\u7EED\u5B8C\u5584\u7684\u5730\u65B9\uFF0C\u8BA9\u6211\u4EEC\u518D\u52A0\u52A0\u73ED\uFF0C\u5C3D\u53EF\u80FD\u5730\u7ED9\u51FA\u4E00\u4E2A\u76F8\u5BF9\u5B8C\u7F8E\u7684\u54CD\u5E94\u5F0F\u6570\u636E\u5B9E\u73B0\u65B9\u6848\u3002</p><h3 id="\u5B8C\u5584\u54CD\u5E94\u7CFB\u7EDF" tabindex="-1"><a class="header-anchor" href="#\u5B8C\u5584\u54CD\u5E94\u7CFB\u7EDF" aria-hidden="true">#</a> \u5B8C\u5584\u54CD\u5E94\u7CFB\u7EDF</h3><h4 id="\u6CDB\u5316\u526F\u4F5C\u7528\u51FD\u6570\u540D" tabindex="-1"><a class="header-anchor" href="#\u6CDB\u5316\u526F\u4F5C\u7528\u51FD\u6570\u540D" aria-hidden="true">#</a> \u6CDB\u5316\u526F\u4F5C\u7528\u51FD\u6570\u540D</h4><p>\u5047\u5982\u6709\u4E00\u5929\uFF0C\u526F\u4F5C\u7528\u7684\u51FD\u6570\u540D\u4E0D\u53EB<code>effect</code>\u4E86\u3002\u800C\u662F\u53EB<code>effect1</code>\u6216\u8005<code>effect2</code>\uFF0C\u751A\u81F3\u526F\u4F5C\u7528\u51FD\u6570\u6CA1\u6709\u76F4\u767D\u7684\u540D\u5B57\u4E86\uFF0C\u53D8\u6210\u4E86\u4E00\u4E2A\u533F\u540D\u51FD\u6570\uFF0C\u90A3\u4E48\u4E0A\u8FF0\u7684\u54CD\u5E94\u7CFB\u7EDF\u65B9\u6848\u663E\u7136\u662F\u884C\u4E0D\u901A\u7684\u3002\u6B64\u65F6\uFF0C\u4E3A\u4E86\u6EE1\u8DB3\u9700\u6C42\uFF0C\u6211\u4EEC\u9700\u8981\u63D0\u4F9B\u4E00\u4E2A\u7528\u6765\u6CE8\u518C\u526F\u4F5C\u7528\u51FD\u6570\u7684\u673A\u5236\uFF0C\u8FBE\u5230\u6CDB\u5316\u526F\u4F5C\u7528\u51FD\u6570\u540D\u7684\u6548\u679C\u3002</p><p>\u6CE8\u518C\u526F\u4F5C\u7528\u51FD\u6570\u540D\u7684\u4EE3\u7801\u793A\u4F8B\u5982\u4E0B\uFF1A</p><p><img src="https://p9-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/895d9a68ae5d4e16bd30ed7d233d8aa2~tplv-k3u1fbpfcp-watermark.image?" alt="carbon (43).png"></p><p>\u8FD9\u6837\uFF0C\u5373\u4F7F\u662F\u4E00\u4E2A\u533F\u540D\u51FD\u6570\uFF0C\u4E5F\u80FD\u591F\u88AB\u6210\u529F\u5730\u6CE8\u518C\u4E3A\u526F\u4F5C\u7528\u51FD\u6570\uFF0C\u6CE8\u518C\u65B9\u6CD5\u5982\u4E0B\uFF1A</p><p><img src="https://p1-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/7d3a93ba11d546aabe7e319bbecbd0e2~tplv-k3u1fbpfcp-watermark.image?" alt="carbon (44).png"></p><p>\u5F53\u7136\uFF0C\u6B64\u65F6\u62E6\u622A\u6570\u636E\u7684\u8BFB\u53D6\u64CD\u4F5C\u4E5F\u9700\u8981\u505A\u7EC6\u5FAE\u7684\u8C03\u6574\uFF1A</p><p><img src="https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/470f7ac1a2d345bfa4628369040eaf13~tplv-k3u1fbpfcp-watermark.image?" alt="carbon (45).png"></p><h4 id="\u4FEE\u590D\u6F0F\u6D1E" tabindex="-1"><a class="header-anchor" href="#\u4FEE\u590D\u6F0F\u6D1E" aria-hidden="true">#</a> \u4FEE\u590D\u6F0F\u6D1E</h4><p>\u5728\u5F88\u591A\u65F6\u5019\uFF0C<code>debug</code>\u90FD\u662F\u6700\u5934\u75BC\u7684\uFF0C\u7279\u522B\u662F\u660E\u660E\u77E5\u9053\u6709<code>bug</code>\uFF0C\u4F46\u5C31\u662F\u627E\u4E0D\u5230\u4FEE\u590D\u7684\u65B9\u6848\uFF0C\u90A3\u79CD\u611F\u89C9\u771F\u7684\u50CF\u5728\u5750\u7262\u2026\u2026</p><p>\u73B0\u5728\u6211\u4EEC\u6765\u8003\u8651\u4E00\u4E2A\u6781\u7AEF\u6761\u4EF6\uFF1A\u5047\u5982\uFF0C\u5728\u54CD\u5E94\u5F0F\u6570\u636E\u5BF9\u8C61<code>obj</code>\u4E0A\u6DFB\u52A0\u4E86\u4E00\u4E2A\u539F\u672C\u4E0D\u5B58\u5728\u7684\u5C5E\u6027\uFF0C\u90A3\u4E48\u4F1A\u53D1\u751F\u4EC0\u4E48\uFF1F\u5982\u679C\u4F60\u5BF9\u524D\u9762\u7684\u5185\u5BB9\u8FD8\u4E0D\u719F\u6089\uFF0C\u53EF\u4EE5\u518D\u8FD4\u56DE\u53BB\u7FFB\u7FFB\u4EE3\u7801\u3002\u4F60\u4F1A\u53D1\u73B0\u4E00\u4E2A\u60CA\u4EBA\u7684\u4E8B\u5B9E\uFF1A\u5728\u54CD\u5E94\u5F0F\u6570\u636E\u5BF9\u8C61<code>obj</code>\u4E0A\u6DFB\u52A0\u4E00\u4E2A\u539F\u672C\u4E0D\u5B58\u5728\u7684\u5C5E\u6027\uFF0C\u4F1A\u5728\u8FD9\u4E2A\u65B0\u6DFB\u52A0\u7684\u5C5E\u6027\u4E0E\u76F8\u5173\u7684\u526F\u4F5C\u7528\u51FD\u6570\u4E4B\u95F4\u5EFA\u7ACB\u54CD\u5E94\u8054\u7CFB\u3002\u51B7\u9759\u4E0B\u6765\u601D\u8003\u4E00\u4E0B\uFF0C\u5176\u5B9E\uFF0C\u5BFC\u81F4\u8BE5\u95EE\u9898\u51FA\u73B0\u7684\u6839\u672C\u539F\u56E0\u662F\uFF0C<strong>\u6CA1\u6709\u5728\u526F\u4F5C\u7528\u51FD\u6570\u4E0E\u88AB\u64CD\u4F5C\u7684\u76EE\u6807\u5B57\u6BB5\u4E4B\u95F4\u5EFA\u7ACB\u660E\u786E\u7684\u8054\u7CFB</strong>\u3002\u90A3\uFF0C\u8BE5\u5982\u4F55\u89E3\u51B3\u5462\uFF1F</p><p>\u4F60\u60F3\u60F3\uFF0C\u5728\u6570\u636E\u7ED3\u6784\u4E2D\u5B58\u4E0D\u5B58\u5728\u4E00\u79CD\u7ED3\u6784\uFF0C\u5B83\u5177\u6709\u4E00\u4E00\u5BF9\u5E94\u7684\u5173\u7CFB\uFF1F\u6709\uFF0C\u5F53\u7136\u6709\uFF0C<strong>\u6620\u5C04</strong>\u5C31\u662F\u3002\u987A\u7740\u8FD9\u4E2A\u601D\u8DEF\uFF0C\u90A3\u6211\u4EEC\u53EF\u4E0D\u53EF\u4EE5\u7528\u6620\u5C04\u7684\u6765\u5EFA\u7ACB\u76EE\u6807\u5B57\u6BB5\u4E0E\u526F\u4F5C\u7528\u51FD\u6570<code>key-value</code>\u5BF9\u5E94\u7684\u5173\u7CFB\uFF1F\u5F53\u7136\u53EF\u4EE5\uFF01\u90A3\u4E48\u6211\u4EEC\u5C31\u53EF\u4EE5\u5148\u628A\u8D1F\u8D23\u50A8\u5B58\u51FD\u6570\u7684\u53D8\u91CF<code>bucket</code>\u58F0\u660E\u4E3A\u4E00\u4E2A\u6620\u5C04<code>Map&lt;target, Map&lt;key, Set()&gt;&gt;</code>\u7528\u6765\u50A8\u5B58<code>\u54CD\u5E94\u5F0F\u6570\u636E\uFF08key\uFF09-\u8BE5\u54CD\u5E94\u5F0F\u6570\u636E\u6240\u6709\u5C5E\u6027\u76F8\u5173\u7684\u526F\u4F5C\u7528\u51FD\u6570(value)</code>\uFF0C\u5176\u4E2D\uFF0C<code>Map&lt;key, Set&gt;</code>\u50A8\u5B58\u7684\u5C31\u662F\u54CD\u5E94\u5F0F\u5BF9\u8C61\u5C5E\u6027\u4E0E\u76F8\u5E94\u7684\u526F\u4F5C\u7528\u51FD\u6570\u96C6\uFF0C\u8FD9\u6837\uFF0C\u4E00\u4E2A\u660E\u786E\u7684\u8054\u7CFB\u5C31\u5EFA\u7ACB\u8D77\u6765\u4E86\u3002\u800C\u5728\u7740\u624B\u4F18\u5316\u54CD\u5E94\u4EE3\u7801\u4E4B\u524D\uFF0C\u6211\u4EEC\u518D\u60F3\u4E00\u60F3\uFF1A<code>bucket</code>\u7528<code>WeakMap</code>\u4F1A\u4E0D\u4F1A\u6BD4\u7528<code>Map</code>\u8981\u66F4\u597D\u4E00\u70B9?\u6211\u5B9E\u8BDD\u76F4\u8BF4\u5427\uFF0C\u5F53\u7136\u5E94\u8BE5\u7528<code>WeakMap</code>\uFF0C\u56E0\u4E3A<code>WeakMap</code>\u7684<code>key</code>\u662F\u5F31\u5F15\u7528\uFF0C\u4E0D\u4F1A\u5F71\u54CD\u5230\u5783\u573E\u56DE\u6536\u5668\u7684\u5DE5\u4F5C\uFF0C\u4F1A\u5728\u5408\u9002\u7684\u65F6\u5019\u88AB\u56DE\u6536\uFF0C\u7528\u5728\u8FD9\u91CC\u66F4\u5408\u9002\u3002</p><p>\u5177\u4F53\u5B9E\u73B0\u4EE3\u7801\u5982\u4E0B\uFF1A</p><p><img src="https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/5fef6f29fea4439a867bbb803190722e~tplv-k3u1fbpfcp-watermark.image?" alt="carbon (46).png"></p><h2 id="\u603B\u7ED3" tabindex="-1"><a class="header-anchor" href="#\u603B\u7ED3" aria-hidden="true">#</a> \u603B\u7ED3</h2><p>\u603B\u7684\u6765\u8BF4\uFF0C\u8981\u60F3\u5B9E\u73B0\u4E00\u4E2A\u54CD\u5E94\u5F0F\u6570\u636E\u5176\u5B9E\u5C31\u662F\u5229\u7528<code>Proxy</code>\u5BF9\u8C61\u4EE3\u7406\u6216\u8005<code>Object.defineProperty</code>\u5BF9\u8C61\u6765\u62E6\u622A\u5BF9\u6570\u636E\u7684\u8BFB\u53D6\u548C\u8BBE\u7F6E\u64CD\u4F5C\u5E76\u4E0E\u76F8\u5E94\u7684\u526F\u4F5C\u7528\u51FD\u6570\u4F5C\u7CBE\u786E\u7ED1\u5B9A\u3002\u90A3\u4E48\uFF0C\u5982\u679C\u73B0\u5728\u8981\u6C42\u4F60\u7528<code>Object.defineProperty</code>\u5BF9\u8C61\u6765\u5B9E\u73B0\u6570\u636E\u54CD\u5E94\uFF0C\u4F60\u80FD\u591F\u72EC\u7ACB\u5B9E\u73B0\u4E86\u5417\uFF1F\u8BD5\u4E00\u4E0B\u5457\uFF01</p>',41);function a(t,p){return o}var f=c(d,[["render",a]]);export{f as default};
